function solve(s) {
    const segments = [];
    const seen = new Set();
    let currentSegment = "";

    for (const char of s) {
        currentSegment += char;
        if (seen.has(currentSegment)) {
            segments.push(currentSegment);
            seen.add(currentSegment);
            currentSegment = "";
        } else {
            seen.add(currentSegment);
        }
    }

    if (currentSegment) {
        segments.push(currentSegment);
    }

    return segments;
}
